#include<bits/stdc++.h>
using namespace std;

int n, k, ant=0;
int a[10001], b[30];
bool zi(int x) {
	for (int i = 2; i * i <= x; i++) {
		if(x % i == 0){
			return false;
		}
	}return true;
}
void f(int x,int l) {
	if (x > k) {
		int num=0;
		for (int i = 1; i <= n; i++) {
			if(b[i]==1){
				num+=a[i];
			}
		} if (zi(num)) {
			ant++;
			return;
		} else {
			return;
		}
	}
	for (int i = l+1; i <= n; i++) {
		b[i]=1;
		f(x+1,i);
		b[i]=0;
	}
}
int main(){
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}f(1,0);
	cout<<ant;
	return 0;
}
